mapper.select:
SELECT a.id, a.period_id, a.student_id, a.honor_type_id, a.honor_name, a.honor_level, a.achieve_time, a.description, a.material_urls, a.bonus_score, a.affect_dimension, a.status, a.apply_time, a.class_reviewer_id, a.class_review_time, a.class_review_comment, a.dept_reviewer_id, a.dept_review_time, a.dept_review_comment, a.school_reviewer_id, a.school_review_time, a.school_review_comment, s.student_no, u.real_name as student_name, c.class_name, o.unit_name as department_name, ht.type_name as honor_type_name, ht.category as honor_category, ep.period_name FROM student_honor_application a LEFT JOIN students s ON a.student_id = s.id LEFT JOIN users u ON s.user_id = u.id LEFT JOIN classes c ON s.class_id = c.id LEFT JOIN org_units o ON c.org_unit_id = o.id LEFT JOIN honor_types ht ON a.honor_type_id = ht.id LEFT JOIN evaluation_periods ep ON a.period_id = ep.id WHERE a.deleted = 0
AND a.period_id = #{query.periodId}
AND u.real_name LIKE CONCAT('%', #{query.studentName}, '%')
AND s.student_no LIKE CONCAT('%', #{query.studentNo}, '%')
AND a.honor_type_id = #{query.honorTypeId}
AND a.status = #{query.status}
AND s.class_id = #{query.classId}
AND c.org_unit_id = #{query.orgUnitId}
ORDER BY a.apply_time DESC

SELECT a.id, a.period_id, a.honor_type_id, a.honor_name, a.honor_level, a.achieve_time, a.bonus_score, a.affect_dimension, a.status, a.apply_time, ht.type_name as honor_type_name, ht.category as honor_category, ep.period_name FROM student_honor_application a LEFT JOIN honor_types ht ON a.honor_type_id = ht.id LEFT JOIN evaluation_periods ep ON a.period_id = ep.id WHERE a.student_id = #{studentId} AND a.deleted = 0
AND a.period_id = #{periodId}
ORDER BY a.apply_time DESC

SELECT * FROM student_honor_application
WHERE student_id = #{studentId}
AND honor_type_id = #{honorTypeId}
AND period_id = #{periodId}
AND deleted = 0
LIMIT 1

SELECT s.student_no as '学号', u.real_name as '姓名', c.class_name as '班级', o.unit_name as '院系', ht.type_name as '荣誉类型', a.honor_name as '荣誉名称', a.honor_level as '荣誉级别', a.achieve_time as '获得时间', a.bonus_score as '加分', CASE a.affect_dimension WHEN 'moral' THEN '德育' WHEN 'intellectual' THEN '智育' WHEN 'physical' THEN '体育' WHEN 'aesthetic' THEN '美育' WHEN 'labor' THEN '劳育' WHEN 'development' THEN '发展素质' ELSE a.affect_dimension END as '影响维度', CASE a.status WHEN 0 THEN '待审核' WHEN 1 THEN '班级通过' WHEN 2 THEN '班级驳回' WHEN 3 THEN '院系通过' WHEN 4 THEN '院系驳回' WHEN 5 THEN '学校通过' WHEN 6 THEN '学校驳回' WHEN 7 THEN '已撤回' ELSE '未知' END as '状态', a.apply_time as '申报时间', a.description as '说明' FROM student_honor_application a LEFT JOIN students s ON a.student_id = s.id LEFT JOIN users u ON s.user_id = u.id LEFT JOIN classes c ON s.class_id = c.id LEFT JOIN org_units o ON c.org_unit_id = o.id LEFT JOIN honor_types ht ON a.honor_type_id = ht.id WHERE a.deleted = 0
AND a.period_id = #{periodId}
AND a.status = #{status}
ORDER BY o.unit_name, c.class_name, s.student_no
